  getValidationMessage(formcontrol, errorkey, lablename, key, skipKey) {
    const errors = formcontrol.errors;
    if (!errors || !errors[errorkey]) {
      return "";
    }
    if (errorkey === "required") {
      return `${lablename} Required`;
    }
    if (errorkey === "email" || errorkey === "pattern") {
      return `Invalid ${lablename}`;
    }
    if (errorkey === "minlength") {
      const length = errors[errorkey].requiredLength;
      return `Enter the data with minimum (${length}) fixed length`;
    }
    if (errorkey === "maxlength" && key !== skipKey) {
      const length = errors[errorkey].requiredLength;
      return `Enter the data with maximum (${length}) fixed length`;
    }
    if (errorkey === "maxlength" && key === skipKey) {
      return `Invalid ${lablename}`;
    }
    return "";
  }
  currencyFormat(value) {
    if (value == null) {
      value = "0";
    } else {
      value = parseFloat(value.toString().replace(/,/g, ""));
    }
    value = value.toLocaleString("en", { useGrouping: false, minimumFractionDigits: 0 });
    let withNegativeData;
    var result;
    let currencyformat;
    currencyformat = this.currencysymbol === "\u20B9" ? "India" : "other";
    if (currencyformat == "India") {
      if (value < 0) {
        let stringData = value.toString();
        withNegativeData = stringData.substring(1, stringData.length);
        result = withNegativeData.toString().split(".");
      } else if (value >= 0) {
        result = value.toString().split(".");
      }
      var lastThree = result[0].substring(result[0].length - 3);
      var otherNumbers = result[0].substring(0, result[0].length - 3);
      if (otherNumbers != "")
        lastThree = "," + lastThree;
      var output2 = otherNumbers.replace(/\B(?=(\d{2})+(?!\d))/g, ",") + lastThree;
      if (result.length > 1) {
        output2 += "." + result[1];
      }
      if (value >= 0) {
        return output2;
      } else if (value < 0) {
        output2 = "-" + output2;
        return output2;
      }
    } else {
      var result = value.toString().split(".");
      var lastThree = result[0].substring(result[0].length - 3);
      var otherNumbers = result[0].substring(0, result[0].length - 3);
      if (otherNumbers != "")
        lastThree = "," + lastThree;
      var output2 = otherNumbers.replace(/\B(?=(\d{3})+(?!\d))/g, ",") + lastThree;
      if (result.length > 1) {
        output2 += "." + result[1];
      }
      return output2;
    }
  }
  getFormatDateNormal(date) {
    if (date != null && date != "" && date != void 0)
      return this.datepipe.transform(date, "yyyy-MM-dd");
    else
      return null;
  }
